import React, { useState } from 'react';
import axios from 'axios';

// Vamos simplificar as props, pois o componente controla o seu próprio estado
function Login() {
    // Para consistência, vamos chamar os estados 'username' e 'password'
    const [username, setUsername] = useState('');
    const [password, setPassword] = useState(''); // ▼▼▼ MUDANÇA 1: Renomeado de 'pass' para 'password'
    const [error, setError] = useState('');

    // Esta função permanece igual
    const handleEmail = (event) => {
        setUsername(event.target.value);
    }
    // ▼▼▼ MUDANÇA 2: Atualiza a função para usar 'setPassword'
    const handlePassword = (event) => {
        setPassword(event.target.value);
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        setError('');

        // Use console.log aqui para depurar e ver o que está a ser enviado
        console.log("A enviar para o backend:", { username, password });

        try {
            const response = await axios.post('http://localhost:8080/login', {
                username: username,
                password: password // ▼▼▼ MUDANÇA 3: Agora envia o 'password' do estado
            });

            console.log('Login bem-sucedido!', response.data);
            localStorage.setItem('token', response.data);

        } catch (err) {
            console.error('Falha no login', err);
            setError('Credenciais inválidas. Por favor, tente novamente.');
        }
    };

    return (
        <div className="login position-absolute top-50 start-50 translate-middle p-4">
            <h2 className="Welcome_text">Welcome back!</h2>
            <div className="login_content p-2">
                <h5 className="Login_text">Email</h5>
                <input
                    className="login_input"
                    type="text"
                    value={username}
                    onChange={handleEmail}
                />
            </div>
            <div className="Password_content p-2">
                <h5 className="Password_text">Password</h5>
                <input
                    className="Password_input"
                    // O tipo deve ser "password" para esconder os caracteres
                    type="password"
                    // ▼▼▼ MUDANÇA 4: Liga o valor e o onChange à mesma variável de estado 'password'
                    value={password}
                    onChange={handlePassword}
                />
                <p className="Forgot_password py-0 m-0">Forgot your password?</p>
            </div>
            <div className="btn_container p-2">
                <button
                    type="button"
                    className="login_btn"
                    onClick={handleSubmit}
                >
                    Login
                </button>
                <p className="Register py-0 m-0">Need an account? <a>Register</a></p>
            </div>
        </div>
    );
}

export default Login;
